#!/usr/bin/env python3
"""TASK-11: Update ARCHITECTURE.md and ARCHITECTURE_STATUS.md to reflect all Phase 5B changes (prelude, run_default, ExecutionMode::direct, downstream_of generic, --local flag)"""
import base64, json, subprocess, sys

TASK_ID = "TASK-11"
STEPS = json.loads('[{"before_b64": "", "after_b64": "", "target": "ARCHITECTURE_STATUS.md", "index": 0}, {"before_b64": "", "after_b64": "", "target": "ARCHITECTURE.md", "index": 1}, {"before_b64": "aW1wbCBFeGVjdXRpb25Nb2RlIHsKICAgIC8vLyBDb252ZW5pZW5jZSBjb25zdHJ1Y3RvciBmb3IgRGlyZWN0IG1vZGUgKFBoYXNlIDVCKQogICAgcHViIGZuIGRpcmVjdChjb21tYW5kOiBpbXBsIEludG88U3RyaW5nPiwgYXJnczogJlsmc3RyXSkgLT4gU2VsZjsKfQ==", "after_b64": "aW1wbCBFeGVjdXRpb25Nb2RlIHsKICAgIC8vLyBDb252ZW5pZW5jZSBjb25zdHJ1Y3RvciBmb3IgRGlyZWN0IG1vZGUgd2l0aCBubyBlbnYgdmFycyBvciB0aW1lb3V0LgogICAgcHViIGZuIGRpcmVjdChjb21tYW5kOiBpbXBsIEludG88U3RyaW5nPiwgYXJnczogJlsmc3RyXSkgLT4gU2VsZjsKfQ==", "target": "ARCHITECTURE.md", "index": 2}, {"before_b64": "cHViIHRyYWl0IFN0YXRlU3RvcmVFeHQ6IFN0YXRlU3RvcmUgewogICAgLy8vIEJGUyBvdmVyIHRhc2tfc3VjY2Vzc29ycyBncmFwaCBmcm9tIGdpdmVuIHN0YXJ0IG5vZGVzIChQaGFzZSA1QjogZ2VuZXJpYyBTKQogICAgZm4gZG93bnN0cmVhbV9vZjxTOiBBc1JlZjxzdHI+Pigmc2VsZiwgc3RhcnQ6ICZbU10pIC0+IFZlYzxTdHJpbmc+Owp9", "after_b64": "", "target": "ARCHITECTURE.md", "index": 3}, {"before_b64": "", "after_b64": "", "target": "ARCHITECTURE.md", "index": 4}, {"before_b64": "IyMjIHJ1bl9kZWZhdWx0OiBDb252ZW5pZW5jZSBSdW5uZXIgKFBoYXNlIDVCKQ==", "after_b64": "IyMjIHJ1bl9kZWZhdWx0OiBDb252ZW5pZW5jZSBSdW5uZXI=", "target": "ARCHITECTURE.md", "index": 5}, {"before_b64": "IyMjIHByZWx1ZGU6IFJlLWV4cG9ydHMgKFBoYXNlIDVCKQ==", "after_b64": "IyMjIHByZWx1ZGU6IFJlLWV4cG9ydHM=", "target": "ARCHITECTURE.md", "index": 6}, {"before_b64": "4pSCICAtIHJ1bl9kZWZhdWx0KCk6IGNvbnZlbmllbmNlIHJ1bm5lciAoUGhhc2UgNUIpICAgICAgICAg4pSCCuKUgiAgLSBwcmVsdWRlOiByZS1leHBvcnRzIGFsbCBjb21tb24gdHlwZXMgKFBoYXNlIDVCKSAgICAgIOKUgg==", "after_b64": "4pSCICAtIHJ1bl9kZWZhdWx0KCk6IGNvbnZlbmllbmNlIHJ1bm5lciAgICAgICAgICAgICAgICAgICAg4pSCCuKUgiAgLSBwcmVsdWRlOiByZS1leHBvcnRzIGFsbCBjb21tb24gdHlwZXMgICAgICAgICAgICAgICAgIOKUgg==", "target": "ARCHITECTURE.md", "index": 7}, {"before_b64": "", "after_b64": "", "target": "ARCHITECTURE.md", "index": 8}]')

for step in STEPS:
    before = base64.b64decode(step["before_b64"]).decode()
    after = base64.b64decode(step["after_b64"]).decode()
    target = step["target"]
    idx = step["index"]

    content = open(target).read()
    if before not in content:
        print(f"FAILED {TASK_ID} change {idx}: pattern not found in {target}", file=sys.stderr)
        print(f"Expected (first 200 chars): {repr(before[:200])}", file=sys.stderr)
        sys.exit(1)

    result = subprocess.run(
        ["sd", "-F", "-A", "-n", "1", before, after, target],
        capture_output=True, text=True,
    )
    if result.returncode != 0:
        print(f"FAILED {TASK_ID} change {idx}: sd error: {result.stderr}", file=sys.stderr)
        sys.exit(result.returncode)

    new_content = open(target).read()
    if after and after not in new_content:
        print(f"FAILED {TASK_ID} change {idx}: replacement not found after apply", file=sys.stderr)
        sys.exit(1)

    print(f"OK {TASK_ID} change {idx}: applied to {target}")

print(f"OK {TASK_ID}: all changes applied")
